def parse_rag_output(crew_result):
    lines = crew_result.raw.split('\n')
    answer = ''
    sources = {}
    parsing_answer = False

    for line in lines:
        if line.startswith('ANSWER:'):
            parsing_answer = True
            answer = line.replace('ANSWER:', '').strip()
        elif line.startswith('SOURCES:'):
            parsing_answer = False
        elif parsing_answer:
            answer += ' ' + line
        elif ':' in line and parsing_answer == False:
            chunk_id, score = line.split(':')
            sources[chunk_id.strip()] = float(score)

    return {'answer': answer, 'sources': sources}

# Execute
result = rag_crew.kickoff(inputs={'query': user_query})
parsed = parse_rag_output(result)
print(parsed['answer'])
print('Sources:', parsed['sources'])

