def vex_synthesis_guard(output, context_chunks):
    verdict = vex.verify(
        claim=output['answer'],
        context=context_chunks,
        checks=[
            'hallucination_detection',
            'source_faithfulness',
            {'name': 'citation_accuracy', 'require_sources': True}
        ],
        risk_profile='high'
    )

    if not verdict.passed:
        return {'error': 'Hallucination detected', 'score': verdict.score}
    return output

