class VexCrewMonitor:
    def __init__(self, vex_client):
        self.vex = vex_client

    def monitor_task(self, task_output, task_context):
        # Multi-check verification
        results = self.vex.batch_verify([
            {'claim': task_output, 'context': task_context, 'checks': ['source_faithfulness']},
            {'claim': task_output, 'context': task_context, 'checks': ['hallucination_detection']}
        ])

        # Block on critical failures
        if any(not r.passed for r in results):
            raise ValueError('Vex verification failed')

        return task_output

